#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long s,t;
    bool operator<(const node&b)const
    {
        if(s+t==b.s+b.t)
        {
            return t<b.t;
        }
        return s+t<b.s+b.t;
    }
}a[200010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n;
        scanf("%lld",&n);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld%lld",&a[i].s,&a[i].t);
        }
        sort(a+1,a+1+n);
        priority_queue<long long> q;
        long long sum=0;
        for(long long i=1;i<=n;i++)
        {
            q.push(a[i].t);
            sum+=a[i].t;
            if(sum-a[i].t>a[i].s)
            {
                sum-=q.top();
                q.pop();
            }
        }
        printf("%d\n",q.size());
    }
    return 0;
}
